noncompliant_example:
void save(Path p, byte[] data) throws IOException {
    Files.write(p, data);
    log.info("saved");
}

compliant_example:
void save(Path p, byte[] data) throws IOException {
    try {
        Files.write(p, data);
        log.info("saved {}", p);
    } catch (IOException e) {
        log.error("failed to save {}", p, e);
        throw e;
    }
}
